import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import AuthLayout from '../components/auth/AuthLayout';

export default function Login() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [adminSecret, setAdminSecret] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      const data = await login(email, password, isAdmin ? 'admin' : 'student', isAdmin ? adminSecret : undefined);
      navigate(data.user.role === 'admin' ? '/admin/dashboard' : '/student/dashboard');
    } catch (err) {
      setError(err.response?.data?.message || 'Invalid email or password.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <AuthLayout
      subtitle="Authorized Access Only"
      footerLink={{ text: "New student?", to: '/signup', label: 'Create account' }}
    >
      <div className="role-tabs">
        <button 
          type="button" 
          className={`role-tab ${!isAdmin ? 'active' : ''}`}
          onClick={() => setIsAdmin(false)}
        >
          🎓 Student
        </button>
        <button 
          type="button" 
          className={`role-tab ${isAdmin ? 'active' : ''}`}
          onClick={() => setIsAdmin(true)}
        >
          🛡️ Officer
        </button>
      </div>

      {error && (
        <div className="login-error">
          <span style={{ fontSize: 16 }}>⚠️</span>
          <span>{error}</span>
        </div>
      )}

      <form onSubmit={handleSubmit}>
        <div className="form-group">
          <label>College Email</label>
          <input 
            className="input-field"
            type="email" 
            value={email} 
            onChange={e => setEmail(e.target.value)} 
            placeholder="name@kec.ac.in"
            required 
          />
        </div>
        <div className="form-group">
          <label>Password</label>
          <input 
            className="input-field"
            type="password" 
            value={password} 
            onChange={e => setPassword(e.target.value)} 
            placeholder="••••••••"
            required 
          />
        </div>

        {isAdmin && (
          <div className="form-group animate-fade">
            <label>Admin Access Code</label>
            <input 
              className="input-field"
              type="password" 
              value={adminSecret} 
              onChange={e => setAdminSecret(e.target.value)} 
              placeholder="System Passcode"
              required 
            />
          </div>
        )}

        <button 
          type="submit" 
          className="btn btn-primary login-submit btn-lg" 
          disabled={loading}
          style={{ marginTop: 12 }}
        >
          {loading ? 'Authenticating...' : `Sign In as ${isAdmin ? 'Officer' : 'Student'}`}
        </button>
      </form>
    </AuthLayout>
  );
}
